"""Базовый класс сигналов, политика дискретизации и валидации."""from __future__ import annotationsfrom typing import Anyimport numpy as npfrom ..core.interfaces import ISignalfrom ..core.types import Signalfrom ..infrastructure.config import CONFIG_ALLOWED_TYPES = {"int", "float", "bool", "enum"}def _check_schema(schema: dict[str, dict[str, Any]]) -> None:    if not isinstance(schema, dict) or not schema:        raise ValueError("params_schema must be a non-empty dict")    for key, spec in schema.items():        if not isinstance(spec, dict):            raise ValueError(f"Param '{key}': spec must be dict")        t = spec.get("type")        if t not in _ALLOWED_TYPES:            raise ValueError(f"Param '{key}': bad 'type' ({t!r})")        if "default" not in spec:            raise ValueError(f"Param '{key}': missing 'default'")        if "label" not in spec or not isinstance(spec["label"], str):            raise ValueError(f"Param '{key}': missing string 'label'")        if t in ("int", "float"):            if "min" not in spec or "max" not in spec:                raise ValueError(f"Param '{key}': numeric requires min/max")            if spec["max"] <= spec["min"]:                raise ValueError(f"Param '{key}': max must be > min")            if not (spec["min"] <= spec["default"] <= spec["max"]):                raise ValueError(f"Param '{key}': default out of [min, max]")        if t == "enum":            choices = spec.get("choices")            if not isinstance(choices, (list, tuple)) or not choices:                raise ValueError(f"Param '{key}': enum requires non-empty 'choices'")            if spec["default"] not in choices:                raise ValueError(f"Param '{key}': default not in choices")def _fill_and_validate(params: dict[str, Any],                       schema: dict[str, dict[str, Any]]) -> dict[str, Any]:    extras = set(params) - set(schema)    if extras:        raise ValueError(f"Unknown params: {sorted(extras)}")    out: dict[str, Any] = {}    for key, spec in schema.items():        raw = params.get(key, spec["default"])        t = spec["type"]        try:            if t == "int":                val: Any = int(raw)            elif t == "float":                val = float(raw)            elif t == "bool":                val = bool(raw)            else:                val = str(raw)        except (TypeError, ValueError) as e:            raise ValueError(f"Param '{key}': cannot cast {raw!r} to {t} ({e})") from e        if t in ("int", "float") and not (spec["min"] <= val <= spec["max"]):            raise ValueError(                f"Param '{key}'={val} out of [{spec['min']}, {spec['max']}]"            )        if t == "enum" and val not in spec["choices"]:            raise ValueError(f"Param '{key}'={val!r} not in {spec['choices']}")        out[key] = val    return outdef _check_below_nyquist(name: str, freq: float, fs: float) -> None:    nyq = 0.5 * fs    if freq >= nyq:        raise ValueError(            f"{name}={freq} Гц должна быть строго меньше Найквиста fs/2={nyq} Гц "            f"(fs={fs} Гц)"        )def _time_axis(duration: float, fs: float) -> np.ndarray:    if fs <= 0:        raise ValueError("fs must be > 0")    if duration <= 0:        raise ValueError("duration must be > 0")    n = int(round(duration * fs))    if n <= 0:        raise ValueError("empty time axis (n_samples == 0)")    if n > CONFIG.max_signal_samples:        raise ValueError(f"n_samples={n} exceeds limit {CONFIG.max_signal_samples}")    return np.arange(n, dtype=np.float64) / float(fs)def _build_signal(t: np.ndarray, x: np.ndarray, fs: float,                  name: str, params: dict[str, Any]) -> Signal:    t_arr = np.asarray(t, dtype=np.float64)    x_arr = np.asarray(x, dtype=np.float64)    if t_arr.ndim != 1 or x_arr.ndim != 1:        raise ValueError("t and x must be 1-D")    if t_arr.size == 0 or x_arr.size == 0:        raise ValueError("empty signal")    if t_arr.size != x_arr.size:        raise ValueError(f"len(t)={t_arr.size} != len(x)={x_arr.size}")    if not np.all(np.isfinite(t_arr)):        raise ValueError("t contains NaN/Inf")    if not np.all(np.isfinite(x_arr)):        raise ValueError("x contains NaN/Inf")    return Signal(t=t_arr, x=x_arr, fs=float(fs), name=name, params=dict(params))class BaseSignal(ISignal):    def __init_subclass__(cls, **kwargs: Any) -> None:        super().__init_subclass__(**kwargs)        schema = getattr(cls, "params_schema", None)        if schema is not None:            _check_schema(schema)        name = getattr(cls, "name", None)        if not isinstance(name, str) or not name.strip():            raise ValueError(f"{cls.__name__}: 'name' must be a non-empty string")        desc = getattr(cls, "description", None)        if not isinstance(desc, str) or not desc:            raise ValueError(f"{cls.__name__}: 'description' must be a non-empty string")    def generate(self, **params: Any) -> Signal:        p = _fill_and_validate(params, self.params_schema)        t, x = self._compute(p)        return _build_signal(t, x, p["fs"], self.name, p)    def _compute(self, p: dict[str, Any]) -> tuple[np.ndarray, np.ndarray]:        raise NotImplementedError